const data = $input.first().json.body || $input.first().json;
const bookingId = data.bookingId || data.booking_id || ('BK-' + Date.now());
const requesterName = data.requesterName || data.requester_name || '';
const requesterEmail = data.requesterEmail || data.requester_email || '';
const requesterDept = data.department || data.dept || 'N/A';
const roomName = data.roomName || data.room_name || '';
const roomCapacity = parseInt(data.roomCapacity || data.room_capacity || 10);
const meetingDate = data.meetingDate || data.meeting_date || '';
const startTime = data.startTime || data.start_time || '';
const endTime = data.endTime || data.end_time || '';
const purpose = data.purpose || '';
const attendees = parseInt(data.attendees || 1);
const priority = data.priority || 'normal';
const equipmentNeeded = data.equipmentNeeded || data.equipment_needed || [];
const managerEmail = data.managerEmail || data.manager_email || 'quanganh.hs2005@gmail.com';
const notes = data.notes || '';

// Tính số giờ họp
let durationHours = 1;
try {
  const [sh, sm] = startTime.split(':').map(Number);
  const [eh, em] = endTime.split(':').map(Number);
  durationHours = ((eh * 60 + em) - (sh * 60 + sm)) / 60;
} catch(e) {}

const valid = !!(requesterEmail && requesterName && roomName && meetingDate && startTime && endTime && durationHours > 0);
const overCapacity = attendees > roomCapacity;
const tooLong = durationHours > 8;

return [{ json: {
  booking_id: bookingId,
  requester_name: requesterName,
  requester_email: requesterEmail,
  requester_dept: requesterDept,
  room_name: roomName,
  room_capacity: roomCapacity,
  meeting_date: meetingDate,
  start_time: startTime,
  end_time: endTime,
  purpose,
  attendees,
  priority,
  equipment_needed: Array.isArray(equipmentNeeded) ? equipmentNeeded.join(', ') : equipmentNeeded,
  manager_email: managerEmail,
  notes,
  duration_hours: durationHours,
  created_at: new Date().toISOString(),
  valid,
  over_capacity: overCapacity,
  too_long: tooLong
}}];

const newStart = $('Normalize & Enrich Dữ liệu').item.json.start_time;
const newEnd = $('Normalize & Enrich Dữ liệu').item.json.end_time;
const existing = $input.all();

function toMinutes(t) {
  const [h, m] = t.split(':').map(Number);
  return h * 60 + m;
}

const newS = toMinutes(newStart);
const newE = toMinutes(newEnd);

let hasConflict = false;
let conflictInfo = null;

for (const item of existing) {
  const exS = toMinutes(item.json.start_time || '00:00');
  const exE = toMinutes(item.json.end_time || '00:00');
  if (newS < exE && newE > exS) {
    hasConflict = true;
    conflictInfo = { conflicting_booking: item.json.booking_id, conflicting_time: item.json.start_time + ' - ' + item.json.end_time };
    break;
  }
}

const base = $('Normalize & Enrich Dữ liệu').item.json;
return [{ json: { ...base, has_conflict: hasConflict, conflict_info: conflictInfo } }];

const now = new Date();
const results = [];
for (const item of $input.all()) {
  const deadline = new Date(item.json.approval_deadline);
  const isExpired = deadline < now;
  const hoursLeft = (deadline - now) / (1000 * 3600);
  if (isExpired) {
    results.push({ json: { ...item.json, action: 'expired' } });
  } else if (hoursLeft <= 2) {
    results.push({ json: { ...item.json, action: 'remind', hours_left: Math.round(hoursLeft * 10) / 10 } });
  }
}
return results;

const q = $input.first().json.query || {};
const bookingId = q.booking_id || '';
const action = q.action || '';
const managerNote = q.note || q.reason || '';
const validActions = ['approve', 'reject'];
return [{ json: { booking_id: bookingId, action, manager_note: managerNote, valid: !!(bookingId && validActions.includes(action)), processed_at: new Date().toISOString() } }];

const approvalData = $('Parse Approval Request').item.json;
const bookingData = $input.first().json;

if (!bookingData || !bookingData.booking_id) {
  return [{ json: { error: true, message: 'Booking không tồn tại' } }];
}

const alreadyProcessed = ['approved','rejected','expired'].includes(bookingData.status);

return [{ json: { ...bookingData, action: approvalData.action, manager_note: approvalData.manager_note, processed_at: approvalData.processed_at, already_processed: alreadyProcessed } }];

const now = new Date();
const todayStr = now.toISOString().split('T')[0];
const results = [];

for (const item of $input.all()) {
  if (item.json.meeting_date !== todayStr) continue;
  const [h, m] = (item.json.start_time || '00:00').split(':').map(Number);
  const meetingTime = new Date(now);
  meetingTime.setHours(h, m, 0, 0);
  const diffMins = (meetingTime - now) / 60000;
  if (diffMins >= 25 && diffMins <= 35) {
    results.push({ json: { ...item.json, minutes_until_meeting: Math.round(diffMins) } });
  }
}
return results;

// Thêm log để debug
const raw = $input.first().json;
const data = raw.body || raw;

console.log('raw:', JSON.stringify(raw));
console.log('data:', JSON.stringify(data));

const bookingId = data.bookingId || data.booking_id || '';
const requesterEmail = data.requesterEmail || data.requester_email || '';
const reason = data.reason || 'Không có lý do';

return [{ json: { 
  booking_id: bookingId, 
  requester_email: requesterEmail, 
  cancel_reason: reason, 
  valid: !!(bookingId && requesterEmail),
  cancelled_at: new Date().toISOString(),
  _debug_raw: raw,
  _debug_bookingId: bookingId,
  _debug_email: requesterEmail
}}];

const cancelData = $('Parse Cancel Request').first().json;
const booking = $input.first().json;

// Debug — xem Sheets trả về field nào
console.log('booking fields:', Object.keys(booking));
console.log('requester_email từ booking:', booking.requester_email);
console.log('requester_email từ cancel:', cancelData.requester_email);

const isOwner = booking.requester_email === cancelData.requester_email;
const canCancel = ['pending', 'pending_urgent', 'approved'].includes(booking.status);

return [{ json: { 
  ...booking, 
  cancel_reason: cancelData.cancel_reason, 
  cancelled_at: cancelData.cancelled_at, 
  status: 'cancelled', 
  can_cancel: canCancel, 
  is_owner: isOwner,
  _debug_isOwner: isOwner,
  _debug_canCancel: canCancel,
  _debug_bookingStatus: booking.status,
  _debug_bookingEmail: booking.requester_email,
  _debug_cancelEmail: cancelData.requester_email
}}];
